# How many satoshis did this transaction pay for fee?: b71fb9ab7707407cc7265591e0c0d47d07afede654f91de1f63c0cb522914bcb
outs=$(bitcoin-cli -signet getrawtransaction b71fb9ab7707407cc7265591e0c0d47d07afede654f91de1f63c0cb522914bcb true | jq '[.vout[].value] | add'); in_tx=$(bitcoin-cli -signet getrawtransaction b71fb9ab7707407cc7265591e0c0d47d07afede654f91de1f63c0cb522914bcb true | jq -r '.vin[0].txid'); in_vout=$(bitcoin-cli -signet getrawtransaction b71fb9ab7707407cc7265591e0c0d47d07afede654f91de1f63c0cb522914bcb true | jq -r '.vin[0].vout'); ins=$(bitcoin-cli -signet getrawtransaction $in_tx true | jq -r --argjson v "$in_vout" '.vout[$v].value'); v_diff=$(echo "$ins - $outs" | bc); echo "$v_diff * 100000000" | bc | cut -d. -f1
